CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) NOT NULL,email VARCHAR(150) UNIQUE NOT NULL,password VARCHAR(255) NOT NULL,status TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE settings (id INT AUTO_INCREMENT PRIMARY KEY,store_name VARCHAR(150),logo VARCHAR(255),phone VARCHAR(30),address VARCHAR(255),default_delivery_fee DECIMAL(10,2) DEFAULT 0,avg_delivery_time INT DEFAULT 45,pix_key VARCHAR(150),whatsapp_template TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE categories (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) NOT NULL,status TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE products (id INT AUTO_INCREMENT PRIMARY KEY,category_id INT,name VARCHAR(120) NOT NULL,description TEXT,price DECIMAL(10,2) NOT NULL,image VARCHAR(255),avg_prep_time INT DEFAULT 20,status TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY(category_id) REFERENCES categories(id) ON DELETE SET NULL);
CREATE TABLE product_addons (id INT AUTO_INCREMENT PRIMARY KEY,product_id INT NULL,name VARCHAR(120) NOT NULL,price DECIMAL(10,2) NOT NULL,status TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE);
CREATE TABLE customers (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,phone VARCHAR(30) UNIQUE,address VARCHAR(255),district VARCHAR(120),reference_note VARCHAR(255),status TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE delivery_drivers (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,phone VARCHAR(30),status TINYINT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE orders (id INT AUTO_INCREMENT PRIMARY KEY,customer_id INT,driver_id INT NULL,order_type ENUM('delivery','retirada','balcao') NOT NULL,payment_method ENUM('dinheiro','pix','cartao','online') NOT NULL,status ENUM('pendente','aceito','em_preparo','pronto_retirada','saiu_entrega','finalizado','cancelado') DEFAULT 'pendente',subtotal DECIMAL(10,2) DEFAULT 0,delivery_fee DECIMAL(10,2) DEFAULT 0,discount DECIMAL(10,2) DEFAULT 0,total DECIMAL(10,2) DEFAULT 0,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY(customer_id) REFERENCES customers(id),FOREIGN KEY(driver_id) REFERENCES delivery_drivers(id));
CREATE TABLE order_items (id INT AUTO_INCREMENT PRIMARY KEY,order_id INT NOT NULL,product_id INT NOT NULL,quantity INT NOT NULL,unit_price DECIMAL(10,2) NOT NULL,total_price DECIMAL(10,2) NOT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE,FOREIGN KEY(product_id) REFERENCES products(id));
CREATE TABLE order_item_addons (id INT AUTO_INCREMENT PRIMARY KEY,order_item_id INT NOT NULL,product_addon_id INT NOT NULL,name VARCHAR(120) NOT NULL,price DECIMAL(10,2) NOT NULL,quantity INT DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(order_item_id) REFERENCES order_items(id) ON DELETE CASCADE,FOREIGN KEY(product_addon_id) REFERENCES product_addons(id));
CREATE TABLE cash_registers (id INT AUTO_INCREMENT PRIMARY KEY,opened_by INT,opened_at DATETIME NOT NULL,closed_at DATETIME NULL,opening_amount DECIMAL(10,2) DEFAULT 0,closing_amount DECIMAL(10,2) NULL,status ENUM('aberto','fechado') DEFAULT 'aberto',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY(opened_by) REFERENCES users(id));
CREATE TABLE cash_movements (id INT AUTO_INCREMENT PRIMARY KEY,cash_register_id INT NOT NULL,type ENUM('entrada','saida') NOT NULL,amount DECIMAL(10,2) NOT NULL,payment_method ENUM('dinheiro','pix','cartao','online') NOT NULL,description VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(cash_register_id) REFERENCES cash_registers(id) ON DELETE CASCADE);
